package com.trademaster.ims.mobile.checkout.model;
import jakarta.persistence.*;import java.math.BigDecimal;import java.time.Instant;
@Entity @Table(name="customer_checkout_reviews",indexes=@Index(name="idx_review_account",columnList="customer_account_id"))public class CheckoutReview{@Id @Column(length=36)private String id;@Column(name="customer_account_id",nullable=false)private Long accountId;@Column(name="address_id",nullable=false)private Long addressId;@Column(name="delivery_method_id",nullable=false)private Long deliveryMethodId;@Column(name="cart_fingerprint",nullable=false,length=64)private String fingerprint;@Column(nullable=false,precision=15,scale=2)private BigDecimal subtotal;@Column(name="tax_total",nullable=false,precision=15,scale=2)private BigDecimal tax;@Column(name="delivery_charge",nullable=false,precision=15,scale=2)private BigDecimal delivery;@Column(name="grand_total",nullable=false,precision=15,scale=2)private BigDecimal total;@Column(name="expires_at",nullable=false)private Instant expiresAt;@Column(nullable=false)private boolean consumed;
 public String getId(){return id;}public void setId(String v){id=v;}public Long getAccountId(){return accountId;}public void setAccountId(Long v){accountId=v;}public Long getAddressId(){return addressId;}public void setAddressId(Long v){addressId=v;}public Long getDeliveryMethodId(){return deliveryMethodId;}public void setDeliveryMethodId(Long v){deliveryMethodId=v;}public String getFingerprint(){return fingerprint;}public void setFingerprint(String v){fingerprint=v;}public BigDecimal getSubtotal(){return subtotal;}public void setSubtotal(BigDecimal v){subtotal=v;}public BigDecimal getTax(){return tax;}public void setTax(BigDecimal v){tax=v;}public BigDecimal getDelivery(){return delivery;}public void setDelivery(BigDecimal v){delivery=v;}public BigDecimal getTotal(){return total;}public void setTotal(BigDecimal v){total=v;}public Instant getExpiresAt(){return expiresAt;}public void setExpiresAt(Instant v){expiresAt=v;}public boolean isConsumed(){return consumed;}public void setConsumed(boolean v){consumed=v;}}
